Bash(node -e "
const { execSync } = require\('child_process'\);

// Simulate what our code does with TMUX_TMPDIR
const output = execSync\('/opt/homebrew/bin/tmux list-sessions -F \\"#{session_name}\\t#{session_attached}\\"', {
  cwd: '/',
  encoding: 'utf-8',
  timeout: 10000,
  env: { ...process.env, TMUX_TMPDIR: '/tmp' },
}\).trim\(\);

console.log\('RAW:', JSON.stringify\(output\)\);

const sessions = output.split\('\\n'\).filter\(Boolean\).map\(line => {
  const [name, attached] = line.split\('\\t'\);
  return { name, attached: attached === '1' };
}\);

console.log\('SESSIONS:', JSON.stringify\(sessions, null, 2\)\);
")

